def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        weight = 1.0 + (item % 3) * 0.1
        primes = [2, 3, 5, 7, 11, 13, 17]
        for m in range(1, 5):
            sub_score = 0
            for j in range(1, 12):
                mul_factor = 1 + 0.05 * (j % 4)
                exp_factor = np.exp(-((ratio + 0.1*m) * j / (m + 1)))
                if (cap + m*j) % primes[j % len(primes)] == 0:
                    mul_factor *= 1.02
                elif (cap * j + m) % 4 == 0:
                    mul_factor *= 0.96
                if ratio < 0.1 * j:
                    sub_score += (j**2) * exp_factor * mul_factor
                elif ratio < 0.5:
                    sub_score += (np.log1p(j * m) * ratio) / (j + m)
                else:
                    sub_score -= (ratio * j) / (m + j)
            if sub_score > 0:
                for k in range(1, m + 3):
                    diff = cap - (item * k * m)
                    if diff == 0:
                        sub_score *= 1.1
                    elif diff > 0 and diff % (k + m) == 0:
                        sub_score += np.sqrt(diff) / (k + 1)
                    elif diff < 0:
                        sub_score -= np.abs(diff)**1.2 / (k + m)
            score += sub_score * weight / (m + 1)
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            if cap < item:
                priorities[i] = -score * np.log1p(item)
            else:
                priorities[i] = -score * np.sqrt(cap + 1)
        else:
            if cap > item * 7:
                priorities[i] = -score / (np.cbrt(cap) + 1)
            elif cap > item * 3:
                priorities[i] = -score / (np.sqrt(cap) + 2)
            else:
                priorities[i] = -score / (cap + 3)
        if ratio > 0.85:
            priorities[i] *= 1.3
            if cap % 2 == 0:
                priorities[i] *= 1.1
        elif ratio < 0.05:
            priorities[i] *= 0.7
            if cap % 5 == 0:
                priorities[i] *= 0.9
        for extra_check in range(1, 4):
            if (cap + extra_check * i) % 6 == 0:
                priorities[i] *= 1.05
            elif (cap * extra_check - i) % 7 == 0:
                priorities[i] *= 0.95
    return priorities
